#include <stdio.h>
#include <math.h>
#define PI 3.14

int main() {
    int T;
    scanf("%d", &T);
    for (int i = 0; i < T; i++) {
        int X;
        scanf("%d", &X);
        int x[X], y[X];
        for (int j = 0; j < X; j++) {
            scanf("%d %d", &x[j], &y[j]);
        }
        double maxArea = 0;
        for (int j = 0; j < X; j++) {
            for (int k = j + 1; k < X; k++) {
                for (int l = k + 1; l < X; l++) {
                    double a = sqrt(pow(x[j] - x[k], 2) + pow(y[j] - y[k], 2));
                    double b = sqrt(pow(x[k] - x[l], 2) + pow(y[k] - y[l], 2));
                    double c = sqrt(pow(x[l] - x[j], 2) + pow(y[l] - y[j], 2));
                    double s = (a + b + c) / 2;
                    double area = sqrt(s * (s - a) * (s - b) * (s - c));
                    if (area > 0) {
                        double R = (a * b * c) / (4 * area);
                        double circumArea = PI * pow(R, 2);
                        if (circumArea > maxArea) {
                            maxArea = circumArea;
                        }
                    }
                }
            }
        }
        if(maxArea == 0) printf("Case %d: -1\n", i + 1);
        else printf("Case %d: %d\n", i + 1, (int)floor(maxArea));
    }
    return 0;
}

