        for (int i = 0; i < T; i++) {
            int X = sc.nextInt();
            int[] x = new int[X];
            int[] y = new int[X];
            for (int j = 0; j < X; j++) {
                x[j] = sc.nextInt();
                y[j] = sc.nextInt();
            }
            double maxArea = 0;
            for (int j = 0; j < X; j++) {
                for (int k = j + 1; k < X; k++) {
                    for (int l = k + 1; l < X; l++) {
                        double a = Math.sqrt(Math.pow(x[j] - x[k], 2) + Math.pow(y[j] - y[k], 2));
                        double b = Math.sqrt(Math.pow(x[k] - x[l], 2) + Math.pow(y[k] - y[l], 2));
                        double c = Math.sqrt(Math.pow(x[l] - x[j], 2) + Math.pow(y[l] - y[j], 2));
                        double s = (a + b + c) / 2;
                        double area = Math.sqrt(s * (s - a) * (s - b) * (s - c));
                        if (area > 0) {
                            double R = (a * b * c) / (4 * area);
                            double circumArea = 3.14 * Math.pow(R, 2);
                            if (circumArea > maxArea) {
                                maxArea = circumArea;
                            }
                        }
                    }
                }
            }
            if(maxArea == 0) System.out.println("Case " + (i + 1) + ": -1");
            else System.out.println("Case " + (i + 1) + ": " + (int)Math.floor(maxArea));
        }
    }
}

